var tintCache={};
function tintedPart(key,color){var byc=tintCache[color]||(tintCache[color]={});if(byc[key])return byc[key];
  var d=RIG_PARTS[key],im=RIG.img[key];var cn=document.createElement("canvas");cn.width=d.w;cn.height=d.h;var cx=cn.getContext("2d");
  cx.drawImage(im,0,0,d.w,d.h);cx.globalCompositeOperation="source-atop";cx.globalAlpha=0.38;cx.fillStyle=color;cx.fillRect(0,0,d.w,d.h);byc[key]=cn;return cn;}
